import { createContext, useContext, useState } from "react";

const OrderContext = createContext();

export function OrderProvider({ children }) {
  const [order, setOrder] = useState([]);

  const addOrder = ({ cartItems, total, shipping, name, phone, address, note, userId, email }) => {
    const newOrder = {
      id: `FM${Date.now()}`,
      date: new Date().toISOString(),
      name,
      phone,
      address,
      note,
      items: cartItems.map((item) => ({ ...item })),
      subtotal: total,
      shipping,
      total: total + shipping,
      status: "confirmed", // confirmed | shipping | delivered | cancelled
      userId: userId,
      email: email,
    };
    setOrder((prev) => [newOrder, ...prev]);
    return newOrder.id;
  };

  const updateOrderStatus = (orderId, newStatus) => {
    setOrder((prev) =>
      prev.map((o) => (o.id === orderId ? { ...o, status: newStatus } : o))
    );
  };

  const getOrdersByUser = (userId, email) => {
    if (!userId && !email) return [];
    return order.filter((o) => o.userId === userId || o.email === email);
  };

  return (
    <OrderContext.Provider value={{ order, addOrder, updateOrderStatus, getOrdersByUser }}>
      {children}
    </OrderContext.Provider>
  );
}

export function useOrder() {
  return useContext(OrderContext);
}
